// // This module implements a D flip-flop with synchronous active-low reset and data disable. When the reset is low, the output q is set to 0. When the enable signal is low, the output q does not follow the input d on the positive edge of the clock.
module d_ff (
	input clk,
	input reset,
	input enable,
	input d,
	output reg q);always @(posedge clk) begin
		if (reset)
			q <= 1'b1;
		else if (enable)
			q <= d;
	end

endmodule
